INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd00100000-0000-0000-0000-00000000001', '大客户经理', '1. - 市场洞察能力\n- 简要定义：深度分析家政服务市场动态与客户需求，挖掘潜在头部客户资源的能力\n- 典型行为表现：通过专业市场调研方法把握行业趋势，筛选锁定具有战略价值的行业头部客户\n2. - 方案设计能力\n- 简要定义：根据客户个性化需求设计定制化合作方案并撰写高质量商业计划书及投标方案的能力\n- 典型行为表现：设计贴合客户期望的服务方案，独立撰写突出公司优势的投标方案以提升中标率\n3. - 商务谈判能力\n- 简要定义：主导商务谈判推动合同签订，监控服务交付质量并协调解决问题以保障客户满意度的能力\n- 典型行为表现：凭借沟通技巧与谈判能力促成合同签订，全程监控服务交付并及时协调解决合作问题\n4. - 资源整合能力\n- 简要定义：拓展内外部生态伙伴资源并整合优势资源，设计创新跨界合作产品的能力\n- 典型行为表现：与上下游企业及相关机构建立合作关系，基于资源整合设计跨界合作产品探索新业务增长点\n5. - 项目管理能力\n- 简要定义：高效组织跨部门团队确保合作项目按时、高质量交付的能力\n- 典型行为表现：组织跨部门团队推进项目，保障合作项目在规定时间内高质量完成交付', '1. - 市场洞察能力\n- 简要定义：深度分析家政服务市场动态与客户需求，挖掘潜在头部客户资源的能力\n- 典型行为表现：通过专业市场调研方法把握行业趋势，筛选锁定具有战略价值的行业头部客户\n2. - 方案设计能力\n- 简要定义：根据客户个性化需求设计定制化合作方案并撰写高质量商业计划书及投标方案的能力\n- 典型行为表现：设计贴合客户期望的服务方案，独立撰写突出公司优势的投标方案以提升中标率\n3. - 商务谈判能力\n- 简要定义：主导商务谈判推动合同签订，监控服务交付质量并协调解决问题以保障客户满意度的能力\n- 典型行为表现：凭借沟通技巧与谈判能力促成合同签订，全程监控服务交付并及时协调解决合作问题\n4. - 资源整合能力\n- 简要定义：拓展内外部生态伙伴资源并整合优势资源，设计创新跨界合作产品的能力\n- 典型行为表现：与上下游企业及相关机构建立合作关系，基于资源整合设计跨界合作产品探索新业务增长点\n5. - 项目管理能力\n- 简要定义：高效组织跨部门团队确保合作项目按时、高质量交付的能力\n- 典型行为表现：组织跨部门团队推进项目，保障合作项目在规定时间内高质量完成交付', '2026-07-09T00:00:00Z');
