INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd00400000-0000-0000-0000-00000000004', '市场BD主管', '请提供需要提取能力维度的正文内容，以便我完成信息提取任务。', '请提供需要提取能力维度的正文内容，以便我完成信息提取任务。', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd00500000-0000-0000-0000-00000000005', '市场BD专员', '1. - 渠道拓展能力\n- 简要定义：对接孕婴行业及相关商家，通过商务谈判拓展线索来源的能力\n- 典型行为表现：根据公司渠道合作政策对接孕婴摄影、母婴店等商家进行合作；多形式展开异业合作项目对接，整合资源获取更多合作方资源\n2. - 客情维护能力\n- 简要定义：维护合作渠道客情关系，提升线索数量及质量的能力\n- 典型行为表现：定期进行产品及政策宣贯培训，保证公司政策及物料落地执行；与合作方策划日常活动方案并跟进落地执行力，确保活动效果\n3. - 数据复盘能力\n- 简要定义：协调跟进线索转化，进行数据分析与复盘的能力\n- 典型行为表现：协调联动销售分区跟进合作方提供的线索转化情况并定期复盘分析；负责城市异业合作的数据分析展示，掌握竞品和行业动向\n4. - 市场洞察能力\n- 简要定义：熟悉当地孕婴市场，掌握行业动态为决策提供信息的能力\n- 典型行为表现：熟悉当地孕婴市场或有相关行业资源；为城市经理提供更多基于竞品和行业动向的市场信息\n5. - 商务谈判能力\n- 简要定义：与合作商家进行商务谈判达成合作的能力\n- 典型行为表现：通过商务谈判与孕婴行业商家进行合作，拓展线索来源；在异业合作项目对接中进行谈判，实现资源整合与联动开发', '1. - 渠道拓展能力\n- 简要定义：对接孕婴行业及相关商家，通过商务谈判拓展线索来源的能力\n- 典型行为表现：根据公司渠道合作政策对接孕婴摄影、母婴店等商家进行合作；多形式展开异业合作项目对接，整合资源获取更多合作方资源\n2. - 客情维护能力\n- 简要定义：维护合作渠道客情关系，提升线索数量及质量的能力\n- 典型行为表现：定期进行产品及政策宣贯培训，保证公司政策及物料落地执行；与合作方策划日常活动方案并跟进落地执行力，确保活动效果\n3. - 数据复盘能力\n- 简要定义：协调跟进线索转化，进行数据分析与复盘的能力\n- 典型行为表现：协调联动销售分区跟进合作方提供的线索转化情况并定期复盘分析；负责城市异业合作的数据分析展示，掌握竞品和行业动向\n4. - 市场洞察能力\n- 简要定义：熟悉当地孕婴市场，掌握行业动态为决策提供信息的能力\n- 典型行为表现：熟悉当地孕婴市场或有相关行业资源；为城市经理提供更多基于竞品和行业动向的市场信息\n5. - 商务谈判能力\n- 简要定义：与合作商家进行商务谈判达成合作的能力\n- 典型行为表现：通过商务谈判与孕婴行业商家进行合作，拓展线索来源；在异业合作项目对接中进行谈判，实现资源整合与联动开发', '2026-07-09T00:00:00Z');
