INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd01000000-0000-0000-0000-00000000010', '招商专员（地招）', '1. - 客户开发能力\n- 简要定义：负责区域内劳动者招募及意向客户跟进签约的能力\n- 典型行为表现：电话、企业微信跟进邀约意向劳动者；接待劳动者考查并沟通签约\n2. - 活动执行能力\n- 简要定义：参与并执行公司各类招商活动的能力\n- 典型行为表现：参与完成公司举办的各类招商活动\n3. - 市场分析能力\n- 简要定义：分析行业及区域市场信息并提出建议的能力\n- 典型行为表现：分析行业内相关信息及所在区域市场信息，并提出建议\n4. - 商务沟通能力\n- 简要定义：具备良好商务礼仪和表达以开展业务沟通的能力\n- 典型行为表现：与劳动者进行有效沟通，展现良好商务礼仪\n5. - 软件操作能力\n- 简要定义：熟练使用office软件处理工作的能力\n- 典型行为表现：会使用office软件完成工作相关文档处理', '1. - 客户开发能力\n- 简要定义：负责区域内劳动者招募及意向客户跟进签约的能力\n- 典型行为表现：电话、企业微信跟进邀约意向劳动者；接待劳动者考查并沟通签约\n2. - 活动执行能力\n- 简要定义：参与并执行公司各类招商活动的能力\n- 典型行为表现：参与完成公司举办的各类招商活动\n3. - 市场分析能力\n- 简要定义：分析行业及区域市场信息并提出建议的能力\n- 典型行为表现：分析行业内相关信息及所在区域市场信息，并提出建议\n4. - 商务沟通能力\n- 简要定义：具备良好商务礼仪和表达以开展业务沟通的能力\n- 典型行为表现：与劳动者进行有效沟通，展现良好商务礼仪\n5. - 软件操作能力\n- 简要定义：熟练使用office软件处理工作的能力\n- 典型行为表现：会使用office软件完成工作相关文档处理', '2026-07-09T00:00:00Z');
