INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd01300000-0000-0000-0000-00000000013', '医疗渠道经理', '请提供需要提取信息的正文内容，以便我按照要求完成能力维度的提取。', '请提供需要提取信息的正文内容，以便我按照要求完成能力维度的提取。', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd01400000-0000-0000-0000-00000000014', '商务专员', '1. - 商务谈判能力\n- 简要定义：在商务活动中与客户进行有效沟通、协商并达成合作的能力\n- 典型行为表现：协助主管进行战略客户的谈判与签约；支持招商专员完成重点谈判，提供行业知识与销售技巧辅助\n2. - 市场开拓能力\n- 简要定义：开发新渠道、拓展合作资源以扩大市场份额的能力\n- 典型行为表现：参与招商空白城市新渠道开发，拓展培训机构、家政公司等合作资源；建立并维护行业人脉网络，挖掘潜在合作机会\n3. - 关系维护能力\n- 简要定义：维持现有合作关系并保障合作稳定持续的能力\n- 典型行为表现：维护现有合作机构关系，保障合作稳定性与持续性\n4. - 项目交付协调\n- 简要定义：跟进项目落地进度并协调各方资源保障项目交付的能力\n- 典型行为表现：完成合作机构的交付协调工作，跟进项目落地进度；协调机构会销课时间与产品线线上培训安排，保障培训服务质量\n5. - 跨部门协作能力\n- 简要定义：与不同部门沟通协调以推动项目目标完成的能力\n- 典型行为表现：跨部门协调资源，推动内部团队配合完成合作项目目标', '1. - 商务谈判能力\n- 简要定义：在商务活动中与客户进行有效沟通、协商并达成合作的能力\n- 典型行为表现：协助主管进行战略客户的谈判与签约；支持招商专员完成重点谈判，提供行业知识与销售技巧辅助\n2. - 市场开拓能力\n- 简要定义：开发新渠道、拓展合作资源以扩大市场份额的能力\n- 典型行为表现：参与招商空白城市新渠道开发，拓展培训机构、家政公司等合作资源；建立并维护行业人脉网络，挖掘潜在合作机会\n3. - 关系维护能力\n- 简要定义：维持现有合作关系并保障合作稳定持续的能力\n- 典型行为表现：维护现有合作机构关系，保障合作稳定性与持续性\n4. - 项目交付协调\n- 简要定义：跟进项目落地进度并协调各方资源保障项目交付的能力\n- 典型行为表现：完成合作机构的交付协调工作，跟进项目落地进度；协调机构会销课时间与产品线线上培训安排，保障培训服务质量\n5. - 跨部门协作能力\n- 简要定义：与不同部门沟通协调以推动项目目标完成的能力\n- 典型行为表现：跨部门协调资源，推动内部团队配合完成合作项目目标', '2026-07-09T00:00:00Z');
