INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd01700000-0000-0000-0000-00000000017', '招商专员', '1. - 沟通协调能力\n- 简要定义：通过电话、微信等方式与意向保姆、月嫂、育婴师阿姨有效沟通，协助其完成资质审核、考试等纳入平台流程的能力\n- 典型行为表现：通过电话向意向阿姨介绍公司资质审核要求和流程，跟进其准备相关材料；利用微信与阿姨沟通考试安排及注意事项\n2. - 渠道拓展能力\n- 简要定义：开拓和维护月子中心、社区医院等渠道，确保定期输送合适家政劳动者的能力\n- 典型行为表现：主动联系本地月子中心进行建联，洽谈合作输送月嫂事宜；与社区医院沟通，建立长期合作关系以获取育婴师推荐资源\n3. - 关系维护能力\n- 简要定义：积极维护与劳动者的关系，以增加转介绍的能力\n- 典型行为表现：定期回访已纳入平台的阿姨，了解其工作情况并提供必要支持；组织线上交流活动，增强阿姨对平台的认同感以促进转介绍\n4. - 信息整合能力\n- 简要定义：对筛选出的意向阿姨信息及渠道资源信息进行整理和有效利用的能力\n- 典型行为表现：将不同渠道获取的阿姨信息进行分类整理，建立信息库以便后续跟进；整合各合作渠道输送劳动者的情况，分析渠道有效性并优化合作策略\n5. - 学习适应能力\n- 简要定义：快速学习公司业务流程、家政行业知识并适应岗位要求的能力\n- 典型行为表现：入职后迅速学习公司资质审核标准和平台操作流程；主动了解家政行业动态和不同岗位阿姨的技能要求，以更好地开展工作', '1. - 沟通协调能力\n- 简要定义：通过电话、微信等方式与意向保姆、月嫂、育婴师阿姨有效沟通，协助其完成资质审核、考试等纳入平台流程的能力\n- 典型行为表现：通过电话向意向阿姨介绍公司资质审核要求和流程，跟进其准备相关材料；利用微信与阿姨沟通考试安排及注意事项\n2. - 渠道拓展能力\n- 简要定义：开拓和维护月子中心、社区医院等渠道，确保定期输送合适家政劳动者的能力\n- 典型行为表现：主动联系本地月子中心进行建联，洽谈合作输送月嫂事宜；与社区医院沟通，建立长期合作关系以获取育婴师推荐资源\n3. - 关系维护能力\n- 简要定义：积极维护与劳动者的关系，以增加转介绍的能力\n- 典型行为表现：定期回访已纳入平台的阿姨，了解其工作情况并提供必要支持；组织线上交流活动，增强阿姨对平台的认同感以促进转介绍\n4. - 信息整合能力\n- 简要定义：对筛选出的意向阿姨信息及渠道资源信息进行整理和有效利用的能力\n- 典型行为表现：将不同渠道获取的阿姨信息进行分类整理，建立信息库以便后续跟进；整合各合作渠道输送劳动者的情况，分析渠道有效性并优化合作策略\n5. - 学习适应能力\n- 简要定义：快速学习公司业务流程、家政行业知识并适应岗位要求的能力\n- 典型行为表现：入职后迅速学习公司资质审核标准和平台操作流程；主动了解家政行业动态和不同岗位阿姨的技能要求，以更好地开展工作', '2026-07-09T00:00:00Z');
