INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02200000-0000-0000-0000-00000000022', '产品运营经理', '1. - AI应用落地能力\n\n- 简要定义：主导AI技术在运营全链路的深度应用，推动AI驱动业务模式创新与效率提升并呈现量化业务价值\n\n- 典型行为表现：推动AI驱动用户增长、转化与服务，重构关键运营环节；清晰阐述如何通过AI推动业务模式创新与效率提升\n\n2. - 产品运营策略能力\n\n- 简要定义：以"AI+数据"双引擎制定家政类产品运营策略，推动0到1项目落地并驱动业务增长\n\n- 典型行为表现：制定家政类产品运营策略，实现运营对业务增长的有效驱动；有运营驱动业务增长的成功案例\n\n3. - 用户增长建设能力\n\n- 简要定义：结合家政服务特点设计不同用户生命周期阶段的增长路径，推动用户获取与复购裂变\n\n- 典型行为表现：设计用户生命周期阶段的增长路径；推动新用户获取、老用户复购裂变\n\n4. - 数据分析优化能力\n\n- 简要定义：监控核心运营指标，通过数据驱动运营策略调整，挖掘用户需求与行为特征并输出分析报告\n\n- 典型行为表现：监控注册转化率、复购率等核心运营指标；挖掘用户需求与行为特征，输出分析报告并提出优化建议\n\n5. - 团队管理建设能力\n\n- 简要定义：负责运营团队目标管理、AI应用思维能力培养及团队能力建设\n\n- 典型行为表现：进行运营团队目标管理；培养团队AI应用思维能力', '1. - AI应用落地能力\n\n- 简要定义：主导AI技术在运营全链路的深度应用，推动AI驱动业务模式创新与效率提升并呈现量化业务价值\n\n- 典型行为表现：推动AI驱动用户增长、转化与服务，重构关键运营环节；清晰阐述如何通过AI推动业务模式创新与效率提升\n\n2. - 产品运营策略能力\n\n- 简要定义：以"AI+数据"双引擎制定家政类产品运营策略，推动0到1项目落地并驱动业务增长\n\n- 典型行为表现：制定家政类产品运营策略，实现运营对业务增长的有效驱动；有运营驱动业务增长的成功案例\n\n3. - 用户增长建设能力\n\n- 简要定义：结合家政服务特点设计不同用户生命周期阶段的增长路径，推动用户获取与复购裂变\n\n- 典型行为表现：设计用户生命周期阶段的增长路径；推动新用户获取、老用户复购裂变\n\n4. - 数据分析优化能力\n\n- 简要定义：监控核心运营指标，通过数据驱动运营策略调整，挖掘用户需求与行为特征并输出分析报告\n\n- 典型行为表现：监控注册转化率、复购率等核心运营指标；挖掘用户需求与行为特征，输出分析报告并提出优化建议\n\n5. - 团队管理建设能力\n\n- 简要定义：负责运营团队目标管理、AI应用思维能力培养及团队能力建设\n\n- 典型行为表现：进行运营团队目标管理；培养团队AI应用思维能力', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02300000-0000-0000-0000-00000000023', '高级JAVA开发', '1. - 后端开发能力\n- 指运用Java及主流框架进行业务系统核心模块设计、开发与维护的能力\n- 参与公司业务系统的Java后端开发，负责核心功能模块的设计、开发与维护；参与系统架构设计、数据库设计及性能优化\n2. - API设计开发能力\n- 指按照规范设计、开发API接口并完成联调优化，支持系统对接的能力\n- 负责API接口设计、开发、联调及优化，支持内部系统及第三方系统对接；熟悉RESTful API设计规范，具备接口开发、第三方系统对接经验\n3. - 数据库应用能力\n- 指熟练使用关系型数据库进行设计、优化及问题排查的能力\n- 熟练使用MySQL、Oracle等关系型数据库，具备数据库设计、SQL优化和问题排查能力\n4. - AI工具应用能力\n- 指理解AI Model及Agent框架，运用AI编程工具辅助研发并推动应用落地的能力\n- 参与AI Agent/小龙虾（OpenClaw）等工具在研发及业务场景中的应用落地；熟悉AI编程工具，习惯使用Claude Code、小龙虾（OpenClaw）或相关Agent产品辅助研发\n5. - 团队协作能力\n- 指与产品、业务及研发团队有效协作，完成需求分析等工作的能力\n- 与产品、业务及研发团队协作，完成需求分析、技术方案设计、功能迭代和系统优化；具备良好的沟通协作能力、需求理解能力和问题闭环能力', '1. - 后端开发能力\n- 指运用Java及主流框架进行业务系统核心模块设计、开发与维护的能力\n- 参与公司业务系统的Java后端开发，负责核心功能模块的设计、开发与维护；参与系统架构设计、数据库设计及性能优化\n2. - API设计开发能力\n- 指按照规范设计、开发API接口并完成联调优化，支持系统对接的能力\n- 负责API接口设计、开发、联调及优化，支持内部系统及第三方系统对接；熟悉RESTful API设计规范，具备接口开发、第三方系统对接经验\n3. - 数据库应用能力\n- 指熟练使用关系型数据库进行设计、优化及问题排查的能力\n- 熟练使用MySQL、Oracle等关系型数据库，具备数据库设计、SQL优化和问题排查能力\n4. - AI工具应用能力\n- 指理解AI Model及Agent框架，运用AI编程工具辅助研发并推动应用落地的能力\n- 参与AI Agent/小龙虾（OpenClaw）等工具在研发及业务场景中的应用落地；熟悉AI编程工具，习惯使用Claude Code、小龙虾（OpenClaw）或相关Agent产品辅助研发\n5. - 团队协作能力\n- 指与产品、业务及研发团队有效协作，完成需求分析等工作的能力\n- 与产品、业务及研发团队协作，完成需求分析、技术方案设计、功能迭代和系统优化；具备良好的沟通协作能力、需求理解能力和问题闭环能力', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02400000-0000-0000-0000-00000000024', '劳动者运营实习生', '1. - 内容策划能力\n- 负责家政阿姨招募类笔记的创意策划与发布，撰写接地气、有吸引力的招募文案以吸引潜在劳动者入驻、认证\n- 创意策划家政阿姨招募类笔记并发布\n2. - 流量分析能力\n- 跟踪各渠道内容数据（曝光、点击、转化率），分析流量来源与用户行为，优化内容提升招募帖的曝光与咨询量\n- 分析流量数据并优化标题、封面、关键词、发布时间等\n3. - 转化优化能力\n- 针对不同招聘渠道测试岗位描述话术、福利亮点、沟通方式，提升从“内容展示”到“求职者主动投递/咨询”的转化效率\n- 测试Boss直聘、社群等渠道的招聘内容并优化转化效率\n4. - 用户沟通能力\n- 及时回复劳动者咨询，引导意向阿姨完成留资或报名，收集反馈并协助迭代运营策略\n- 回复劳动者咨询并引导完成留资或报名', '1. - 内容策划能力\n- 负责家政阿姨招募类笔记的创意策划与发布，撰写接地气、有吸引力的招募文案以吸引潜在劳动者入驻、认证\n- 创意策划家政阿姨招募类笔记并发布\n2. - 流量分析能力\n- 跟踪各渠道内容数据（曝光、点击、转化率），分析流量来源与用户行为，优化内容提升招募帖的曝光与咨询量\n- 分析流量数据并优化标题、封面、关键词、发布时间等\n3. - 转化优化能力\n- 针对不同招聘渠道测试岗位描述话术、福利亮点、沟通方式，提升从“内容展示”到“求职者主动投递/咨询”的转化效率\n- 测试Boss直聘、社群等渠道的招聘内容并优化转化效率\n4. - 用户沟通能力\n- 及时回复劳动者咨询，引导意向阿姨完成留资或报名，收集反馈并协助迭代运营策略\n- 回复劳动者咨询并引导完成留资或报名', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02500000-0000-0000-0000-00000000025', '母婴顾问', '1. - 专业咨询能力\n- 为客户提供母婴相关专业咨询和服务的能力\n- 针对需要看阿姨的客户筛选月嫂推荐面试\n2. - 客户关系维护\n- 与客户建立良好关系并熟悉、挖掘客户需求的能力\n- 促进线上签约，邀约到店面谈并接待客户促成线下签约\n3. - 问题处理能力\n- 及时处理客户投诉、安排接单及回答疑难问题的能力\n- 处理客户投诉，回答客户疑难问题以提高客户满意度\n4. - 营销技能提升\n- 参与培训并提升营销技能和工作效率的能力\n- 定期参加公司营销培训、系统使用培训\n5. - 抗压积极能力\n- 具备良好抗压能力并保持积极性的能力\n- 快速调整心态，保持强烈赚钱欲望和积极性', '1. - 专业咨询能力\n- 为客户提供母婴相关专业咨询和服务的能力\n- 针对需要看阿姨的客户筛选月嫂推荐面试\n2. - 客户关系维护\n- 与客户建立良好关系并熟悉、挖掘客户需求的能力\n- 促进线上签约，邀约到店面谈并接待客户促成线下签约\n3. - 问题处理能力\n- 及时处理客户投诉、安排接单及回答疑难问题的能力\n- 处理客户投诉，回答客户疑难问题以提高客户满意度\n4. - 营销技能提升\n- 参与培训并提升营销技能和工作效率的能力\n- 定期参加公司营销培训、系统使用培训\n5. - 抗压积极能力\n- 具备良好抗压能力并保持积极性的能力\n- 快速调整心态，保持强烈赚钱欲望和积极性', '2026-07-09T00:00:00Z');
