INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02700000-0000-0000-0000-00000000027', '母婴顾问', '1. - 专业咨询能力\n- 为客户提供母婴相关专业咨询和服务的能力\n- 针对需要看阿姨的客户筛选月嫂推荐面试\n2. - 客户关系维护\n- 与客户建立良好关系并熟悉、挖掘客户需求的能力\n- 促进线上签约，邀约到店面谈并接待客户促成线下签约\n3. - 问题处理能力\n- 及时处理客户投诉、安排接单及回答疑难问题的能力\n- 处理客户投诉，回答客户疑难问题以提高客户满意度\n4. - 营销技能提升\n- 参与培训并提升营销技能和工作效率的能力\n- 定期参加公司营销培训、系统使用培训\n5. - 抗压积极能力\n- 具备良好抗压能力并保持积极性的能力\n- 快速调整心态，保持强烈赚钱欲望和积极性', '1. - 专业咨询能力\n- 为客户提供母婴相关专业咨询和服务的能力\n- 针对需要看阿姨的客户筛选月嫂推荐面试\n2. - 客户关系维护\n- 与客户建立良好关系并熟悉、挖掘客户需求的能力\n- 促进线上签约，邀约到店面谈并接待客户促成线下签约\n3. - 问题处理能力\n- 及时处理客户投诉、安排接单及回答疑难问题的能力\n- 处理客户投诉，回答客户疑难问题以提高客户满意度\n4. - 营销技能提升\n- 参与培训并提升营销技能和工作效率的能力\n- 定期参加公司营销培训、系统使用培训\n5. - 抗压积极能力\n- 具备良好抗压能力并保持积极性的能力\n- 快速调整心态，保持强烈赚钱欲望和积极性', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd02800000-0000-0000-0000-00000000028', '招商专员（CJF）', '1. 渠道拓展能力\n- 简要定义：通过线上线下多渠道招募阿姨及开发商家合作的能力\n- 典型行为表现：通过电话、社群、家政公司合作等渠道招募保姆、月嫂、育婴师；开发家政公司、培训机构等劳动者输送合作渠道\n2. 资源维护能力\n- 简要定义：同时维护阿姨和商家两类资源并建立长期合作关系的能力\n- 典型行为表现：帮阿姨完成平台入驻流程，建立长期合作关系；跟进合作商家的履约情况，持续优化资源供给\n3. 沟通协调能力\n- 简要定义：与阿姨和商家有效沟通并促成合作的能力\n- 典型行为表现：制定商家合作方案，谈判分成机制，签订合作协议；善沟通会来事，喜欢和人打交道，有耐心\n4. 活动组织能力\n- 简要定义：组织社群活动提升招募效率的能力\n- 典型行为表现：维护阿姨社群，组织转介绍活动提升招募效率\n5. 资源整合能力\n- 简要定义：整合各类资源为岗位服务的意识与能力\n- 典型行为表现：有资源整合意识，能同时维护阿姨和商家两类资源；利用家政行业资源（养老院/社区/月子中心等）开展工作', '1. 渠道拓展能力\n- 简要定义：通过线上线下多渠道招募阿姨及开发商家合作的能力\n- 典型行为表现：通过电话、社群、家政公司合作等渠道招募保姆、月嫂、育婴师；开发家政公司、培训机构等劳动者输送合作渠道\n2. 资源维护能力\n- 简要定义：同时维护阿姨和商家两类资源并建立长期合作关系的能力\n- 典型行为表现：帮阿姨完成平台入驻流程，建立长期合作关系；跟进合作商家的履约情况，持续优化资源供给\n3. 沟通协调能力\n- 简要定义：与阿姨和商家有效沟通并促成合作的能力\n- 典型行为表现：制定商家合作方案，谈判分成机制，签订合作协议；善沟通会来事，喜欢和人打交道，有耐心\n4. 活动组织能力\n- 简要定义：组织社群活动提升招募效率的能力\n- 典型行为表现：维护阿姨社群，组织转介绍活动提升招募效率\n5. 资源整合能力\n- 简要定义：整合各类资源为岗位服务的意识与能力\n- 典型行为表现：有资源整合意识，能同时维护阿姨和商家两类资源；利用家政行业资源（养老院/社区/月子中心等）开展工作', '2026-07-09T00:00:00Z');
