INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd03000000-0000-0000-0000-00000000030', '新媒体运营', '1. - 平台拓客能力\n- 简要定义：通过小红书、抖音等线上平台主动寻找目标用户并获取客户线索的能力\n- 典型行为表现：在小红书、抖音等平台对目标用户进行评论互动、私信沟通；成功获取客户的预产期和联系方式等线索并转交给销售顾问跟进\n2. - 视频制作能力\n- 简要定义：参与视频选题策划，独立完成母婴相关宣发视频拍摄与剪辑的能力\n- 典型行为表现：参与视频选题策划并独立完成拍摄与剪辑工作；对母婴话题有感知力，能捕捉有温度的内容瞬间进行宣发\n3. - 公号运营能力\n- 简要定义：负责公众号内容编辑、发布及将专业内容转化为有温度文字的能力\n- 典型行为表现：负责公众号内容的编辑与发布；具备基础排版能力，能把专业内容转化成有温度的文字\n4. - 直播执行能力\n- 简要定义：参与直播执行或辅助场控，保障不同形式母婴直播顺利进行的能力\n- 典型行为表现：每周参与3场（每场1小时）直播，负责直播执行或辅助场控；参与月嫂访谈、育儿答疑、客户连麦等形式的直播引流工作\n5. - 抗压学习能力\n- 简要定义：在结果导向的工作节奏中保持目标感，并主动学习新媒体运营知识的能力\n- 典型行为表现：有目标感，能接受以结果为导向的工作节奏；愿意主动学习，对新媒体运营有热情，对母婴行业有兴趣', '1. - 平台拓客能力\n- 简要定义：通过小红书、抖音等线上平台主动寻找目标用户并获取客户线索的能力\n- 典型行为表现：在小红书、抖音等平台对目标用户进行评论互动、私信沟通；成功获取客户的预产期和联系方式等线索并转交给销售顾问跟进\n2. - 视频制作能力\n- 简要定义：参与视频选题策划，独立完成母婴相关宣发视频拍摄与剪辑的能力\n- 典型行为表现：参与视频选题策划并独立完成拍摄与剪辑工作；对母婴话题有感知力，能捕捉有温度的内容瞬间进行宣发\n3. - 公号运营能力\n- 简要定义：负责公众号内容编辑、发布及将专业内容转化为有温度文字的能力\n- 典型行为表现：负责公众号内容的编辑与发布；具备基础排版能力，能把专业内容转化成有温度的文字\n4. - 直播执行能力\n- 简要定义：参与直播执行或辅助场控，保障不同形式母婴直播顺利进行的能力\n- 典型行为表现：每周参与3场（每场1小时）直播，负责直播执行或辅助场控；参与月嫂访谈、育儿答疑、客户连麦等形式的直播引流工作\n5. - 抗压学习能力\n- 简要定义：在结果导向的工作节奏中保持目标感，并主动学习新媒体运营知识的能力\n- 典型行为表现：有目标感，能接受以结果为导向的工作节奏；愿意主动学习，对新媒体运营有热情，对母婴行业有兴趣', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd03100000-0000-0000-0000-00000000031', '新媒体运营', '1. - 平台拓客能力\n- 简要定义：通过小红书、抖音等线上平台主动寻找目标用户并获取客户线索的能力\n- 典型行为表现：在小红书、抖音等平台对目标用户进行评论互动、私信沟通；成功获取客户的预产期和联系方式等线索并转交给销售顾问跟进\n2. - 视频制作能力\n- 简要定义：参与视频选题策划，独立完成母婴相关宣发视频拍摄与剪辑的能力\n- 典型行为表现：参与视频选题策划并独立完成拍摄与剪辑工作；对母婴话题有感知力，能捕捉有温度的内容瞬间进行宣发\n3. - 公号运营能力\n- 简要定义：负责公众号内容编辑、发布及将专业内容转化为有温度文字的能力\n- 典型行为表现：负责公众号内容的编辑与发布；具备基础排版能力，能把专业内容转化成有温度的文字\n4. - 直播执行能力\n- 简要定义：参与直播执行或辅助场控，保障不同形式母婴直播顺利进行的能力\n- 典型行为表现：每周参与3场（每场1小时）直播，负责直播执行或辅助场控；参与月嫂访谈、育儿答疑、客户连麦等形式的直播引流工作\n5. - 抗压学习能力\n- 简要定义：在结果导向的工作节奏中保持目标感，并主动学习新媒体运营知识的能力\n- 典型行为表现：有目标感，能接受以结果为导向的工作节奏；愿意主动学习，对新媒体运营有热情，对母婴行业有兴趣', '1. - 平台拓客能力\n- 简要定义：通过小红书、抖音等线上平台主动寻找目标用户并获取客户线索的能力\n- 典型行为表现：在小红书、抖音等平台对目标用户进行评论互动、私信沟通；成功获取客户的预产期和联系方式等线索并转交给销售顾问跟进\n2. - 视频制作能力\n- 简要定义：参与视频选题策划，独立完成母婴相关宣发视频拍摄与剪辑的能力\n- 典型行为表现：参与视频选题策划并独立完成拍摄与剪辑工作；对母婴话题有感知力，能捕捉有温度的内容瞬间进行宣发\n3. - 公号运营能力\n- 简要定义：负责公众号内容编辑、发布及将专业内容转化为有温度文字的能力\n- 典型行为表现：负责公众号内容的编辑与发布；具备基础排版能力，能把专业内容转化成有温度的文字\n4. - 直播执行能力\n- 简要定义：参与直播执行或辅助场控，保障不同形式母婴直播顺利进行的能力\n- 典型行为表现：每周参与3场（每场1小时）直播，负责直播执行或辅助场控；参与月嫂访谈、育儿答疑、客户连麦等形式的直播引流工作\n5. - 抗压学习能力\n- 简要定义：在结果导向的工作节奏中保持目标感，并主动学习新媒体运营知识的能力\n- 典型行为表现：有目标感，能接受以结果为导向的工作节奏；愿意主动学习，对新媒体运营有热情，对母婴行业有兴趣', '2026-07-09T00:00:00Z');
INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd03200000-0000-0000-0000-00000000032', '商家运营专员', '1. - 人员维护能力\n- 简要定义：负责月嫂日常事务管理及薪资物料发放的能力\n- 典型行为表现：进行月嫂工资、奖金、路费、物料的发放\n2. - 订单安排能力\n- 简要定义：合理安排月嫂和育婴师订单及换单的能力\n- 典型行为表现：处理月嫂、育婴师正常订单、换单安排\n3. - 基础培训能力\n- 简要定义：对月嫂和育婴师开展非专业培训的能力\n- 典型行为表现：开展月嫂、育婴师非专业培训\n4. - 应急对接能力\n- 简要定义：协助处理急单对接及售后问题的能力\n- 典型行为表现：协助顾问急单的对接，处理云管家售后\n5. - 沟通协作能力\n- 简要定义：具备良好沟通能力及团队合作精神的能力\n- 典型行为表现：性格开朗善于沟通，具有团队精神，接受非工作时间信息回复', '1. - 人员维护能力\n- 简要定义：负责月嫂日常事务管理及薪资物料发放的能力\n- 典型行为表现：进行月嫂工资、奖金、路费、物料的发放\n2. - 订单安排能力\n- 简要定义：合理安排月嫂和育婴师订单及换单的能力\n- 典型行为表现：处理月嫂、育婴师正常订单、换单安排\n3. - 基础培训能力\n- 简要定义：对月嫂和育婴师开展非专业培训的能力\n- 典型行为表现：开展月嫂、育婴师非专业培训\n4. - 应急对接能力\n- 简要定义：协助处理急单对接及售后问题的能力\n- 典型行为表现：协助顾问急单的对接，处理云管家售后\n5. - 沟通协作能力\n- 简要定义：具备良好沟通能力及团队合作精神的能力\n- 典型行为表现：性格开朗善于沟通，具有团队精神，接受非工作时间信息回复', '2026-07-09T00:00:00Z');
