INSERT INTO capability_dimensions (id, position_name, full_text, behavior, created_at) VALUES ('cd03500000-0000-0000-0000-00000000035', '社群用户运营专员', '1. - 社群运营能力\n- 负责社群日常管理，提升用户活跃度的能力\n- 进行用户答疑、氛围维护、活动发布及规则同步\n2. - 数据处理能力\n- 跟踪并复盘数据，辅助优化运营策略的能力\n- 更新关键指标，每日输出运营数据报表\n3. - 渠道管理能力\n- 管理转介绍渠道，处理线索及活动触达的能力\n- 负责转介绍渠道端线索录入，整理月度营销活动触达转介绍用户\n4. - 协作沟通能力\n- 与友商及合作部门沟通，保障事务有序进行的能力\n- 活动返佣、礼品按规则有序发放，与友商及合作部门保持良好沟通\n5. - 执行推进能力\n- 主动跟进问题，高效完成任务的能力\n- 主动跟进问题不推诿不拖延，主动push待办事项', '1. - 社群运营能力\n- 负责社群日常管理，提升用户活跃度的能力\n- 进行用户答疑、氛围维护、活动发布及规则同步\n2. - 数据处理能力\n- 跟踪并复盘数据，辅助优化运营策略的能力\n- 更新关键指标，每日输出运营数据报表\n3. - 渠道管理能力\n- 管理转介绍渠道，处理线索及活动触达的能力\n- 负责转介绍渠道端线索录入，整理月度营销活动触达转介绍用户\n4. - 协作沟通能力\n- 与友商及合作部门沟通，保障事务有序进行的能力\n- 活动返佣、礼品按规则有序发放，与友商及合作部门保持良好沟通\n5. - 执行推进能力\n- 主动跟进问题，高效完成任务的能力\n- 主动跟进问题不推诿不拖延，主动push待办事项', '2026-07-09T00:00:00Z');
